import{_ as l,o as r,c as t,j as e,a as p,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const b=JSON.parse('{"title":"法术宝石Spell Gem","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/2.C级/法术宝石Spell Gem.md","filePath":"4.资源分区/7.物品与装备/4.奇物/2.C级/法术宝石Spell Gem.md"}'),n={name:"4.资源分区/7.物品与装备/4.奇物/2.C级/法术宝石Spell Gem.md"};function o(d,a,_,m,i,c){return r(),t("div",null,[...a[0]||(a[0]=[e("h1",{id:"法术宝石spell-gem",tabindex:"-1"},[p("法术宝石Spell Gem "),e("a",{class:"header-anchor",href:"#法术宝石spell-gem","aria-label":'Permalink to "法术宝石Spell Gem"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘")])])],-1),s('<h1 id="法术宝石spell-gem-1" tabindex="-1">法术宝石Spell Gem <a class="header-anchor" href="#法术宝石spell-gem-1" aria-label="Permalink to &quot;法术宝石Spell Gem&quot;">​</a></h1><p>法术宝石Spell Gem<br> C+1000<br> 魔幻本质<br> 购买时需要在戒指/护符中选择一种装备位置，主神会将宝石制作成合适的物品让购买者可佩戴在对应装备位上。<br> 一枚法术宝石可以储存一种C及C以下的通用消耗魔力的法术，在购买时确定。任何得到该宝石的人，都会在得知宝石的属性后知晓其内含法术的具体状况。持握宝石时，你可以消耗一个相应动作与一发充能施展该法术，即使你不具备魔力和施法者权限。法术宝石具有18点魔力，使用其中储存的法术会消耗其中储存的魔力，在使用所有的魔力后，如想再释放，则需要从自身的魔力池中扣除，同理，法术宝石也可以为使用者供给魔力，每天结束时，法术宝石会自动恢复所有储存的魔力。<br> 通过宝石释放的法术的视为拥有C级【预设】的特性，但你只能使用法术宝石释放储存的法术。</p><p>这些法术宝石由地底侏儒制作而成，不过他们并不愿意跟别人分享这种秘密工艺。</p><p>st选开：<br> st可以允许pl在每个影片结束后的休息时间内，更改宝石内储存的法术。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',6)])])}const S=l(n,[["render",o]]);export{b as __pageData,S as default};
